import React, { useEffect, useRef } from "react";
import "./DynamicBackground.css";

// Returns a dark base with a shining radial highlight
const getShiningGradient = (x = 50, y = 50) => {
  return `
    radial-gradient(circle at ${x}% ${y}%, rgba(255,255,255,0.12) 0%, rgba(34,34,34,0.9) 60%, #111 100%)
  `;
};

function DynamicBackground() {
  const bgRef = useRef(null);

  useEffect(() => {
    const handleMouseMove = (e) => {
      if (!bgRef.current) return;
      const { innerWidth, innerHeight } = window;
      const x = (e.clientX / innerWidth) * 100;
      const y = (e.clientY / innerHeight) * 100;
      bgRef.current.style.backgroundImage = getShiningGradient(x, y);
    };

    window.addEventListener("mousemove", handleMouseMove);

    // Set initial gradient
    if (bgRef.current) {
      bgRef.current.style.backgroundImage = getShiningGradient();
    }

    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, []);

  return (
    <div
      ref={bgRef}
      className="dynamic-bg"
      aria-hidden="true"
      tabIndex={-1}
    />
  );
}

export default DynamicBackground;
